import { chromium } from "playwright";
const logo = "data:image/svg+xml;base64,";
const html = `<!doctype html><html><head><meta charset="utf8"><style>
*{margin:0;box-sizing:border-box}
body{width:1200px;height:630px;background:#0a0b0e;color:#e7e9ee;
 font-family:-apple-system,system-ui,sans-serif;overflow:hidden;position:relative}
.grid{position:absolute;inset:0;background-image:
 linear-gradient(rgba(255,255,255,.04) 1px,transparent 1px),
 linear-gradient(90deg,rgba(255,255,255,.04) 1px,transparent 1px);background-size:48px 48px}
.glow{position:absolute;top:-200px;right:-100px;width:700px;height:600px;
 background:radial-gradient(circle,rgba(255,67,56,.22),transparent 60%)}
.wrap{position:relative;padding:90px;height:100%;display:flex;flex-direction:column;justify-content:center}
.top{display:flex;align-items:center;gap:22px;margin-bottom:36px}
img{width:84px;height:84px}
.name{font-family:ui-monospace,monospace;font-size:54px;font-weight:800;letter-spacing:-2px}
.name b{color:#ff4338}
h1{font-size:84px;line-height:1.02;font-weight:800;letter-spacing:-3px;max-width:980px}
.g{background:linear-gradient(110deg,#fff,#ff4338 70%,#fcaf3e);-webkit-background-clip:text;color:transparent}
p{margin-top:34px;font-size:30px;color:#9aa0ab;max-width:880px;line-height:1.4}
.k{font-family:ui-monospace,monospace;color:#ff4338;font-size:22px;letter-spacing:3px;margin-bottom:20px}
</style></head><body>
<div class="grid"></div><div class="glow"></div>
<div class="wrap">
 <div class="top"><img src="${logo}"><span class="name">angr<b>_</b></span></div>
 <div class="k">// OPEN-SOURCE BINARY ANALYSIS</div>
 <h1>Take binaries <span class="g">apart.</span></h1>
 <p>Symbolic execution, decompilation &amp; CFG recovery — a Python-native platform for every architecture.</p>
</div></body></html>`;
const b = await chromium.launch();
const p = await (await b.newContext({viewport:{width:1200,height:630},deviceScaleFactor:1})).newPage();
await p.setContent(html,{waitUntil:"networkidle"});
await p.screenshot({path:"public/og.png"});
console.log("og.png written");
await b.close();
